def minimum_initial_points_to_reach_destination(dungeon: list[list[int]]) -> int:
    R = len(dungeon)
    C = len(dungeon[0])

    dp = [[0] * C for _ in range(R)]

    # Calculate for the destination cell (R-1, C-1)
    dp[R - 1][C - 1] = max(1, 1 - dungeon[R - 1][C - 1])

    # Fill the last row (from right to left)
    for j in range(C - 2, -1, -1):
        dp[R - 1][j] = max(1, dp[R - 1][j + 1] - dungeon[R - 1][j])

    # Fill the last column (from bottom to top)
    for i in range(R - 2, -1, -1):
        dp[i][C - 1] = max(1, dp[i + 1][C - 1] - dungeon[i][C - 1])

    # Fill the rest of the grid (from bottom-right to top-left)
    for i in range(R - 2, -1, -1):
        for j in range(C - 2, -1, -1):
            dp[i][j] = min(
                max(1, dp[i][j + 1] - dungeon[i][j]),  # Path going right
                max(1, dp[i + 1][j] - dungeon[i][j])   # Path going down
            )

    return dp[0][0]
